public class InstanceInit {
    int x;
    {
        x = 5;
        System.out.println("instance init: x=" + x);
    }
    InstanceInit() {
        System.out.println("constructor: x=" + x);
    }
    InstanceInit(int v) {
        x = v;
        System.out.println("constructor(int): x=" + x);
    }
    public static void main(String[] args) {
        new InstanceInit();
        new InstanceInit(99);
    }
}
